import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api';

const ManageAdmins = () => {
  const [admins, setAdmins] = useState([]);
  const [showAddForm, setShowAddForm] = useState(false);
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    phone: '',
    role: 'Admin'
  });
  const navigate = useNavigate();

  useEffect(() => {
    checkSuperAdmin();
    fetchAdmins();
  }, []);

  const checkSuperAdmin = () => {
    const adminData = localStorage.getItem('adminUser');
    if (!adminData) {
      alert('Please login as admin');
      navigate('/admin/login');
      return;
    }
    
    const admin = JSON.parse(adminData);
    if (admin.role !== 'Super Admin') {
      alert('Access denied. Super Admin only.');
      navigate('/admin/dashboard');
    }
  };

  const fetchAdmins = async () => {
    try {
      const response = await API.get('/admin/all-admins');
      if (response.data.success) {
        setAdmins(response.data.admins);
      }
    } catch (error) {
      console.error('Error fetching admins:', error);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleAddAdmin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const response = await API.post('/admin/create-admin', formData);
      if (response.data.success) {
        alert('Admin created successfully!');
        setShowAddForm(false);
        setFormData({
          name: '',
          email: '',
          password: '',
          phone: '',
          role: 'Admin'
        });
        fetchAdmins(); // Refresh list
      }
    } catch (error) {
      console.error('Error creating admin:', error.response?.data);
      alert(error.response?.data?.message || 'Failed to create admin');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteAdmin = async (adminId, adminEmail) => {
    if (!window.confirm(`Are you sure you want to delete ${adminEmail}?`)) {
      return;
    }

    try {
      const response = await API.delete(`/admin/delete-admin/${adminId}`);
      if (response.data.success) {
        alert('Admin deleted successfully');
        fetchAdmins(); // Refresh list
      }
    } catch (error) {
      console.error('Error deleting admin:', error.response?.data);
      alert(error.response?.data?.message || 'Failed to delete admin');
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>👑 Manage Administrators</h1>
        <button 
          onClick={() => setShowAddForm(!showAddForm)} 
          style={styles.addButton}
        >
          {showAddForm ? '✕ Cancel' : '➕ Add New Admin'}
        </button>
      </div>

      {/* Add Admin Form */}
      {showAddForm && (
        <div style={styles.formCard}>
          <h2 style={styles.formTitle}>Create New Administrator</h2>
          <form onSubmit={handleAddAdmin}>
            <div style={styles.formGrid}>
              <div style={styles.formGroup}>
                <label style={styles.label}>Full Name *</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  style={styles.input}
                  placeholder="Enter full name"
                  required
                />
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Email Address *</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  style={styles.input}
                  placeholder="admin@kdmc.gov"
                  required
                />
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Phone Number *</label>
                <input
                  type="tel"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  style={styles.input}
                  placeholder="10-digit number"
                  pattern="[0-9]{10}"
                  required
                />
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Role *</label>
                <select
                  name="role"
                  value={formData.role}
                  onChange={handleChange}
                  style={styles.input}
                  required
                >
                  <option value="Admin">Admin</option>
                  <option value="Super Admin">Super Admin</option>
                  <option value="Moderator">Moderator</option>
                </select>
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Temporary Password *</label>
                <input
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  style={styles.input}
                  placeholder="Min 6 characters"
                  minLength="6"
                  required
                />
                <small style={styles.helpText}>
                  Admin should change this after first login
                </small>
              </div>
            </div>

            <button type="submit" style={styles.submitButton} disabled={loading}>
              {loading ? 'Creating...' : 'Create Administrator'}
            </button>
          </form>
        </div>
      )}

      {/* Admins List */}
      <div style={styles.listCard}>
        <h2 style={styles.listTitle}>All Administrators ({admins.length})</h2>
        
        {admins.length === 0 ? (
          <p style={styles.emptyText}>No administrators found.</p>
        ) : (
          <div style={styles.table}>
            {/* Table Header */}
            <div style={styles.tableHeader}>
              <div style={{ flex: 2 }}>Name</div>
              <div style={{ flex: 2 }}>Email</div>
              <div style={{ flex: 1 }}>Phone</div>
              <div style={{ flex: 1 }}>Role</div>
              <div style={{ flex: 1 }}>Actions</div>
            </div>

            {/* Table Rows */}
            {admins.map((admin) => (
              <div key={admin._id} style={styles.tableRow}>
                <div style={{ flex: 2, fontWeight: 'bold' }}>{admin.name}</div>
                <div style={{ flex: 2 }}>{admin.email}</div>
                <div style={{ flex: 1 }}>{admin.phone}</div>
                <div style={{ flex: 1 }}>
                  <span style={admin.role === 'Super Admin' ? styles.superAdminBadge : styles.adminBadge}>
                    {admin.role === 'Super Admin' ? '👑' : '🔑'} {admin.role}
                  </span>
                </div>
                <div style={{ flex: 1 }}>
                  {admin.role !== 'Super Admin' && (
                    <button
                      onClick={() => handleDeleteAdmin(admin._id, admin.email)}
                      style={styles.deleteButton}
                    >
                      🗑️ Delete
                    </button>
                  )}
                  {admin.role === 'Super Admin' && (
                    <span style={{ fontSize: '12px', color: '#999' }}>Protected</span>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

